from flask import request
import re


@app.route("/direct")
def direct():
    pattern = request.args.get('pattern', '')
    text = request.args.get('text', '')

    # Enforce max length to prevent ReDoS (CWE-400/CWE-730)
    if len(pattern) > 100:
        return "Pattern too long", 400

    # Validate pattern is safe: only alphanumeric, spaces, and basic punctuation
    # This prevents regex injection and ReDoS by disallowing dangerous metacharacters
    safe_pattern = r'^[a-zA-Z0-9\s\.\^\$\-\_\:\,]+$'
    if not re.match(safe_pattern, pattern):
        return "Invalid pattern", 400

    try:
        compiled_pattern = re.compile(pattern)
        match = compiled_pattern.search(text)
        if match:
            return match.group(0)
        return "No match"
    except re.error:
        return "Invalid pattern", 400

